```uniface
entry plCalcularValorTotalProdutos

params

    struct pstcEntrada : IN
        ->produtos: COLLECTION OF STRUCT

endparams

; Inicializa variável para armazenar valor total
numeric vValorTotal = 0;

for (numeric vProduto = 1 to pstcEntrada->produtos->$collSize) {
    ; Obtém o produto atual
    struct vProdutoStruct = pstcEntrada->produtos->{vProduto};

    ; Realiza multiplicação do valor com a quantidade e soma no valor total
    vValorTotal += (vProdutoStruct->$scalar(1).$value * vProdutoStruct->$scalar(2).$value);
}

; Retorna o valor total
return (vValorTotal);
end;
```
