column19:
    ; Variáveis locais
    numeric vMédia : local;

begin

    ; Valida se os parâmetros estão dentro do range de 0 a 10
    if (pNota1 < 0 || pNota1 > 10) or
       (pNota2 < 0 || pNota2 > 10) or
       (pNota3 < 0 || pNota3 > 10) or
       (pNota4 < 0 || pNota4 > 10) or
       (pMínimaAprovação < 0 || pMínimaAprovação > 10)
    then
        ; Retorna um erro
        result.aprovado = false;
        return(-1);
    endIf;

    ; Calcula a média das notas
    vMédia = (pNota1 + pNota2 + pNota3 + pNota4) / 4;

    ; Verifica se a média está acima da mínima aprovação
    if (vMédia >= pMínimaAprovação)
        then
            ; Aprovado!
            result.aprovado = true;
        else
            ; Reprovado!
            result.aprovado = false;
    endIf;

    ; Retorna o resultado
    result.média = vMédia;
    return(0);

end.
```

Essa operação aceita 4 parâmetros de notas e um parâmetro de média mínima de aprovação. Ela valida se os parâmetros estão dentro do range de 0 a 10

