```sql
BEGIN
  IF p_valor < 0 THEN
    -- Tratar erro: valor não pode ser negativo
    p_desconto_acrescimo := 0;
    p_subtotal := 0;
  ELSIF p_valor <= 10 THEN
    -- Desconto para valores baixos (10% do subtotal)
    p_desconto_acrescimo := p_valor * 0.1;
    p_subtotal := p_valor - p_desconto_acrescimo;
  ELSE
    -- Acrescimo para valores altos (5% do subtotal)
    p_desconto_acrescimo := p_valor * 0.05;
    p_subtotal := p_valor + p_desconto_acrescimo;
  END IF;
END validar_valor_subtotal;
```
